const tableData = {{workflowparams:tableData}}

const currentIndexRaw = {{node:get_cache_node_ioyNVXF7.data}}
const index = currentIndexRaw ? parseInt(currentIndexRaw, 10) : 0

const item = tableData[index];
const material_id = item.material_id;

return {
  item: item,
  material_id: material_id,
  index: index,
  nextIndex: index + 1
}

const parseJsonSafely = (jsonString, defaultValue = []) => {
  try {
    return jsonString ? JSON.parse(jsonString) : defaultValue;
  } catch (error) {
    return defaultValue;
  }
};

const item = {{node:code_node_gG7AZrE1.data.item}}
const itemMaster = {{node:get_node_kXaJ7CW6.data.data}}
const isPickingPlan = {{workflowparams:isPickingPlan}} || null
const isGDPP = {{workflowparams:isGDPP}} || 0;

const material_id = item.material_id;
const material_uom = isPickingPlan ? item.to_order_uom_id || item.picking_plan_uom_id : item.gd_order_uom_id || item.good_delivery_uom_id;
const parent_id = item.line_so_id || "";
const parent_line_id = item.so_line_item_id || "";
const parent_no = item.line_so_no || "";
const doc_line_id = item.id || "";
const remark = item.line_remark_1 || "";
const picking_plan_id = item.line_pp_id || "";
const picking_plan_line_id = item.pp_line_item_id||"";
const picking_id = item.line_to_id || "";

const isBatchManagedItem = itemMaster.item_batch_management === 1;
const temporaryData = parseJsonSafely(item.temp_qty_data);

let message = null;
let code = null;

if (
  temporaryData.length === 0
) {
  message = `No temp_qty_data to process for item ${item.material_name}`;
  code = "200";
}

// GROUP temp_qty_data by location + batch combination
const groupedTempData = {};

for (const temp of temporaryData) {
  const groupKey =
    isBatchManagedItem && temp.batch_id
      ? `${temp.location_id}|${temp.batch_id}`
      : temp.location_id;

  if (!groupedTempData[groupKey]) {
    groupedTempData[groupKey] = {
      location_id: temp.location_id,
      batch_id: temp.batch_id || null,
      totalQty: 0,
    };
  }

  groupedTempData[groupKey].totalQty += parseFloat(
    temp.gd_quantity || temp.to_quantity || temp.quantity || 0,
  );
}

const groupKeys = Object.keys(groupedTempData);

return {
  message: message,
  code: code,
  groupKeys: groupKeys,
  groupedTempData: groupedTempData,
  material_id: material_id,
  material_uom: material_uom,
  parent_id: parent_id,
  parent_line_id: parent_line_id,
  parent_no: parent_no,
  doc_line_id: doc_line_id,
  picking_plan_id: picking_plan_id,
  picking_plan_line_id: picking_plan_line_id,
  picking_id: picking_id,
  remark: remark,
  isGDPP: isGDPP,
};

const roundQty = (value) => parseFloat(parseFloat(value || 0).toFixed(3));

const groupKeys = {{node:code_node_ra24gKwq.data.groupKeys}}
const groupedTempData = {{node:code_node_ra24gKwq.data.groupedTempData}}

const currentIndexRaw = {{node:get_cache_node_Oci70e87.data}}
const index = currentIndexRaw ? parseInt(currentIndexRaw, 10) : 0;
const groupKey = groupKeys[index];
const group = groupedTempData[groupKey];

const currentQty = roundQty(group.totalQty);

return {
  quantity: currentQty,
  location_id: group.location_id,
  batch_id: group.batch_id || null,
  index: index,
  nextIndex: index + 1,
};

const isGDPP = {{workflowparams:isGDPP}} || 0;
let allocatedData = []
if (isGDPP === 1) {
  allocatedData = {{node:search_node_30auReet.data.data}}
} else {
  allocatedData = {{node:search_node_fz18zvlp.data.data}}
}

return {
  isGDPP,
  allocatedData
}

const currentAllocatedRecords = {{node:search_node_ndtbikhX.data}};
const existingPendingRecords = {{node:search_node_9I7tIzli.data}};
const tableData = {{workflowparams:tableData}};

if (!currentAllocatedRecords.data || currentAllocatedRecords.data.length === 0) {
  return {
    code: "200",
    recordsToUpdate: [],
    recordsToUpdateLength: 0,
    inventoryMovements: [],
    inventoryMovementsLength: 0,
    message: "No cleanup needed - no allocated records found",
  };
}

const currentTempDataKeys = tableData.flatMap((line) => {
  const tempData =
    typeof line.temp_qty_data === "string"
      ? JSON.parse(line.temp_qty_data || "[]")
      : line.temp_qty_data || [];

  return tempData.map((td) => ({
    doc_line_id: line.id,
    material_id: td.material_id,
    batch_id: td.batch_id,
    bin_location: td.location_id,
  }));
});

const orphanedRecords = currentAllocatedRecords.data.filter(
  (allocated) =>
    !currentTempDataKeys.some(
      (current) =>
        String(allocated.doc_line_id) === String(current.doc_line_id) &&
        String(allocated.material_id) === String(current.material_id) &&
        String(allocated.batch_id || "") === String(current.batch_id || "") &&
        String(allocated.bin_location || "") === String(current.bin_location || ""),
    ),
);

if (orphanedRecords.length === 0) {
  return {
    code: "200",
    recordsToUpdate: [],
    recordsToUpdateLength: 0,
    inventoryMovements: [],
    inventoryMovementsLength: 0,
    message: "No orphaned allocations found",
  };
}

const releaseOrderPriority = {
  "Good Delivery": 1,
  "Picking Plan": 1,
  "Sales Order": 2,
  "Production": 3,
};
const sortedOrphanedRecords = [...orphanedRecords].sort(
  (a, b) =>
    (releaseOrderPriority[a.doc_type] || 99) -
    (releaseOrderPriority[b.doc_type] || 99),
);

const findExistingPendingToMerge = (docType, parentLineId, materialId, batchId, binLocation) => {
  const pendingData = existingPendingRecords?.data || [];
  return pendingData.find(
    (record) =>
      record.status === "Pending" &&
      record.doc_type === docType &&
      String(record.parent_line_id) === String(parentLineId) &&
      String(record.material_id) === String(materialId) &&
      String(record.batch_id || "") === String(batchId || "") &&
      String(record.bin_location || "") === String(binLocation || ""),
  );
};

const pendingMergeAccumulator = new Map();
const recordsToUpdate = [];
const inventoryMovementMap = new Map();

for (const orphanedRecord of sortedOrphanedRecords) {
  const releaseQty = orphanedRecord.reserved_qty || 0;

  if (orphanedRecord.doc_type === "Good Delivery" || orphanedRecord.doc_type === "Picking Plan") {
    recordsToUpdate.push({
      id: orphanedRecord.id,
      reserved_qty: orphanedRecord.reserved_qty,
      open_qty: 0,
      status: "Cancelled",
      target_gd_id: null,
    });

    const invKey = `${orphanedRecord.material_id}|${orphanedRecord.batch_id || ""}|${orphanedRecord.bin_location || ""}`;
    const existingMovement = inventoryMovementMap.get(invKey);
    if (existingMovement) {
      existingMovement.quantity += releaseQty;
    } else {
      inventoryMovementMap.set(invKey, {
        material_id: orphanedRecord.material_id,
        batch_id: orphanedRecord.batch_id,
        bin_location: orphanedRecord.bin_location,
        material_uom: orphanedRecord.item_uom,
        quantity: releaseQty,
        movement_type: "RESERVED_TO_UNRESTRICTED",
      });
    }
  } else {
    const existingPending = findExistingPendingToMerge(
      orphanedRecord.doc_type,
      orphanedRecord.parent_line_id,
      orphanedRecord.material_id,
      orphanedRecord.batch_id,
      orphanedRecord.bin_location,
    );

    if (existingPending) {
      const accumulatedQty = pendingMergeAccumulator.get(existingPending.id) || 0;
      const newAccumulatedQty = accumulatedQty + releaseQty;
      pendingMergeAccumulator.set(existingPending.id, newAccumulatedQty);

      recordsToUpdate.push({
        id: orphanedRecord.id,
        reserved_qty: orphanedRecord.reserved_qty,
        open_qty: 0,
        status: "Cancelled",
        target_gd_id: null,
      });
    } else {
      recordsToUpdate.push({
        ...orphanedRecord,
        doc_id: "",
        doc_no: "",
        doc_line_id: "",
        status: "Pending",
        target_gd_id: null,
      });
    }
  }
}

for (const [pendingId, accumulatedQty] of pendingMergeAccumulator.entries()) {
  const existingPending = (existingPendingRecords?.data || []).find(
    (r) => String(r.id) === String(pendingId),
  );
  if (existingPending) {
    recordsToUpdate.push({
      id: pendingId,
      reserved_qty: existingPending.reserved_qty + accumulatedQty,
      open_qty: existingPending.open_qty + accumulatedQty,
      status: "Pending",
    });
  }
}

const inventoryMovements = Array.from(inventoryMovementMap.values());

return {
  code: "200",
  recordsToUpdate: recordsToUpdate,
  recordsToUpdateLength: recordsToUpdate.length,
  inventoryMovements: inventoryMovements,
  inventoryMovementsLength: inventoryMovements.length,
  message: `Found ${orphanedRecords.length} orphaned allocations to process`,
};

const inventoryMovements = {{node:code_node_xUK0UwrB.data.inventoryMovements}};
const currentIndexRaw = {{node:get_cache_node_hPqoFfrM.data}};
const index = currentIndexRaw ? parseInt(currentIndexRaw, 10) : 0;

const inventory = inventoryMovements[index];

let batchId = inventory.batch_id
if (!batchId || batchId === "") {
  batchId = null
}

const material_id = inventory.material_id;
const location_id = inventory.bin_location;
const batch_id = batchId;
const material_uom = inventory.material_uom;
const quantity = inventory.quantity;
const movement_type = inventory.movement_type;

return {
  material_id: material_id,
  location_id: location_id,
  batch_id: batch_id,
  material_uom: material_uom,
  quantity: quantity,
  movement_type: movement_type,
  index: index,
  nextIndex: index + 1
}

const tableData = {{workflowparams:tableData}};
const pickingRecordUpdates = [];
const pickingIdsSet = new Set();

for (const item of tableData) {
  if (item.line_to_id) {
    pickingIdsSet.add(item.line_to_id);
  }

  if (!item.temp_qty_data) continue;

  try {
    const tempData = JSON.parse(item.temp_qty_data);
    for (const temp of tempData) {
      if (temp.picking_record_id) {
        const qty = parseFloat(temp.gd_quantity || temp.to_quantity || 0);
        pickingRecordUpdates.push({
          id: temp.picking_record_id,
          qty: qty,
        });
      }
    }
  } catch (e) {
    console.error("Error parsing temp_qty_data:", e);
  }
}

const pickingIds = Array.from(pickingIdsSet);

return {
  pickingRecordUpdates: pickingRecordUpdates,
  pickingIds: pickingIds,
};

const pickingRecordUpdates = {{node:code_node_swuVYCVw.data.pickingRecordUpdates}};
const pickings = {{node:search_node_2Bcop3DP.data.data}};

// Create a map of picking_record_id -> qty being delivered
const updateMap = new Map();
for (const update of pickingRecordUpdates) {
  updateMap.set(update.id, update.qty);
}

const recordUpdates = [];
const headerUpdates = [];

for (const picking of pickings) {
  const allRecords = picking.table_picking_records || [];

  let allCompleted = true;
  let anyDelivered = false;

  for (const record of allRecords) {
    const storeOutQty = parseFloat(record.store_out_qty || 0);
    const existingDelivered = parseFloat(record.delivered_qty || 0);

    // Check if this record is being updated
    const additionalQty = updateMap.get(record.id) || 0;
    const newDeliveredQty = existingDelivered + additionalQty;

    // Calculate record delivery_status
    let recordDeliveryStatus;
    if (newDeliveredQty >= storeOutQty) {
      recordDeliveryStatus = "Fully Delivered";
    } else if (newDeliveredQty > 0) {
      recordDeliveryStatus = "Partially Delivered";
    } else {
      recordDeliveryStatus = "";
    }

    // Only add to recordUpdates if this record is being updated
    if (additionalQty > 0) {
      recordUpdates.push({
        id: record.id,
        delivered_qty: newDeliveredQty,
        delivery_status: recordDeliveryStatus,
      });
    }

    // Track for header status calculation (use new values)
    if (newDeliveredQty > 0) anyDelivered = true;
    if (newDeliveredQty < storeOutQty) allCompleted = false;
  }

  // Calculate header delivery_status
  let headerDeliveryStatus;
  if (allCompleted && anyDelivered) {
    headerDeliveryStatus = "Fully Delivered";
  } else if (anyDelivered) {
    headerDeliveryStatus = "Partially Delivered";
  } else {
    headerDeliveryStatus = "";
  }

  headerUpdates.push({
    id: picking.id,
    delivery_status: headerDeliveryStatus,
  });
}

return {
  recordUpdates: recordUpdates,
  isRecord: recordUpdates.length > 0 ? 1 : 0,
  headerUpdates: headerUpdates,
  isHeader: headerUpdates.length > 0 ? 1 : 0,
};
